import React, { useState, useEffect } from 'react';
import { View, Button, Text, ActivityIndicator } from 'react-native';
import { authorize, refresh } from 'react-native-app-auth';

const config = {
  clientId: 'your_client_id',
  clientSecret: 'your_client_secret',
  redirectUrl: 'yourapp://callback',
  scopes: ['openid', 'profile', 'email'],
  serviceConfiguration: {
    authorizationEndpoint: 'https://your-oauth-server.com/auth',
    tokenEndpoint: 'https://your-oauth-server.com/token',
    revocationEndpoint: 'https://your-oauth-server.com/revoke'
  }
};

const App = () => {
  const [authState, setAuthState] = useState(null);
  const [loading, setLoading] = useState(false);

  const authorizeUser = async () => {
    try {
      setLoading(true);
      const authResult = await authorize(config);
      setAuthState(authResult);
    } catch (error) {
      console.error('Failed to authorize', error);
    } finally {
      setLoading(false);
    }
  };

  const refreshToken = async () => {
    try {
      if (!authState || !authState.refreshToken) {
        throw new Error('No refresh token available');
      }
      setLoading(true);
      const authResult = await refresh(config, {
        refreshToken: authState.refreshToken,
      });
      setAuthState(authResult);
    } catch (error) {
      console.error('Failed to refresh token', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (authState && authState.accessTokenExpirationDate) {
      const expiration = new Date(authState.accessTokenExpirationDate);
      const now = new Date();
      const delay = expiration.getTime() - now.getTime() - 5000; // refresh 5 seconds before expiration

      const timeoutId = setTimeout(refreshToken, delay);
      return () => clearTimeout(timeoutId);
    }
  }, [authState]);

  return (
    <View>
      {loading ? (
        <ActivityIndicator size="large" color="#0000ff" />
      ) : authState ? (
        <Text>AccessToken: {authState.accessToken}</Text>
      ) : (
        <Button title="Login" onPress={authorizeUser} />
      )}
    </View>
  );
};

export default App;